#include<stdio.h>
int main()
{
	int i,j,n,k,x,a[100],b[100]={0},num,count=0,flag=0,max=-1,sum=0;
	scanf("%d%d%d",&n,&k,&x);
	for(i=0;i<n;i++)
	{
		scanf("%d",&num);
		if(count>0)
		{
			if(a[count-1]==num)
			{
				b[count-1]++;
			}
			else
			{
				a[count]=num;
				b[count]++;
				count++;
			}
		}
		else
		{
			a[count]=num;
			b[count]++;
			count++;
		}
	}
	for(i=0;i<count;i++)
	{
		if(x==a[i]&&b[i]==2)
		{
			sum=2;
			j=i-1;
			k=i+1;
			flag=0;
			while(j>=0&&k<count&&flag==0)
			{
				if(a[j]==a[k]&&b[j]+b[k]>2)
				{
					sum+=b[j]+b[k];
				}
				else
				{
					flag=1;
				}
				j--;
				k++;
			}
		}
		if(max<sum)
		{
			max=sum;
		}
	}
	printf("%d\n",max);
	return 0;
}

