macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn solve_one(pos: usize, col: usize, c: &Vec<usize>) -> usize {
    let mut s = Vec::new();
    let mut result = 0;
    for i in 0..=c.len() {
        let val = if i < pos {c[i]} else if i > pos {c[i - 1]} else {col};
        if s.is_empty() {
            s.push((val, 1));
        }else if s.last().unwrap().0 == val {
            s.last_mut().unwrap().1 += 1;
        }else{
            if s.last().unwrap().1 > 2 {
                result += s.pop().unwrap().1;
            }
            if s.is_empty() {
                s.push((val, 1));
            }else if s.last().unwrap().0 == val {
                s.last_mut().unwrap().1 += 1;
            }else{
                s.push((val, 1));
            }
        }
    }
    if let Some((_col, cnt)) = s.last() {
        if *cnt > 2 {
            result += cnt;
        }
    }
    return if result > 0 {
        result - 1
    }else{
        0
    }
}

fn solve() {
    let (n, _k, x) = parse_line!(usize, usize, usize);
    let c = parse_line_to_vec!(usize);
    let mut result = 0;
    for i in 0..=n {
        result = std::cmp::max(result, solve_one(i, x, &c));
    }
    println!("{}", result)
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
